mapper.select:
SELECT model_version, user_id, embedding_dim, CAST(embedding_vector AS CHAR) AS embedding_vector
FROM user_embeddings
WHERE model_version = #{modelVersion}

SELECT model_version, item_id, embedding_dim, CAST(embedding_vector AS CHAR) AS embedding_vector
FROM item_embeddings
WHERE model_version = #{modelVersion}

SELECT model_version, user_id, embedding_dim, CAST(embedding_vector AS CHAR) AS embedding_vector
FROM user_embeddings
WHERE model_version = #{modelVersion}
  AND user_id = #{userId}
LIMIT 1

SELECT COUNT(*)
FROM explicit_ratings
WHERE user_id = #{userId}

SELECT item_id,
       COUNT(*) AS exposure_count,
       MAX(request_time) AS last_request_time
FROM rec_results
WHERE user_id = #{userId}
  AND request_time >= #{fromTime}
  AND request_time  <  #{toTime}
GROUP BY item_id
ORDER BY last_request_time DESC, item_id ASC

mapper.delete:
DELETE FROM rec_results
WHERE user_id = #{userId}
  AND request_time >= #{fromTime}
